class Solution:
    def oddEvenJumps(self, arr):
        # Independent approach: brute-force each jump target by a direct O(n) scan
        # (no monotonic stack), then memoized backward reachability.
        n = len(arr)
        odd_t = [None] * n
        even_t = [None] * n
        for i in range(n):
            ot = None; ot_val = None
            et = None; et_val = None
            for j in range(i + 1, n):
                if arr[j] >= arr[i] and (ot is None or arr[j] < ot_val):
                    ot_val = arr[j]; ot = j
                if arr[j] <= arr[i] and (et is None or arr[j] > et_val):
                    et_val = arr[j]; et = j
            odd_t[i] = ot; even_t[i] = et
        odd = [False] * n
        even = [False] * n
        odd[n - 1] = even[n - 1] = True
        for i in range(n - 2, -1, -1):
            if odd_t[i] is not None:
                odd[i] = even[odd_t[i]]
            if even_t[i] is not None:
                even[i] = odd[even_t[i]]
        return sum(1 for v in odd if v)

