var oddEvenJumps = function(arr) {
    const n = arr.length;
    function make(indices) {
        const result = new Array(n).fill(-1);
        const stack = [];
        for (const i of indices) {
            while (stack.length && i > stack[stack.length - 1]) {
                result[stack.pop()] = i;
            }
            stack.push(i);
        }
        return result;
    }
    const idxAsc = Array.from({length: n}, (_, i) => i).sort((a, b) => arr[a] - arr[b] || a - b);
    const oddNext = make(idxAsc);
    const idxDesc = Array.from({length: n}, (_, i) => i).sort((a, b) => arr[b] - arr[a] || a - b);
    const evenNext = make(idxDesc);
    const odd = new Array(n).fill(false);
    const even = new Array(n).fill(false);
    odd[n - 1] = true; even[n - 1] = true;
    for (let i = n - 2; i >= 0; i--) {
        if (oddNext[i] !== -1) odd[i] = even[oddNext[i]];
        if (evenNext[i] !== -1) even[i] = odd[evenNext[i]];
    }
    return odd.reduce((s, v) => s + (v ? 1 : 0), 0);
};
